package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"runtime"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the appropriate ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if the command failed due to non-zero exit status (which is normal for ping)
		// Ping returns exit code 0 on success, but may return other codes if packets are lost
		// We still want to parse the output if we got some results
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue parsing even if there's an error, as ping may have partial results
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Handle different ping output formats
		if strings.Contains(line, "rtt min/avg/max") || 
		   strings.Contains(line, "round-trip min/avg/max") ||
		   (runtime.GOOS == "windows" && strings.Contains(line, "Average =")) {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	var avg float64
	var errParse error

	// Parse based on operating system
	if runtime.GOOS == "windows" {
		// Windows ping output format: "Average = 23ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from Windows ping output")
		}
		avgStr := matches[1]
		avg, errParse = strconv.ParseFloat(avgStr, 64)
	} else {
		// Unix/Linux ping output format: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
		re := regexp.MustCompile(`rtt min/avg/max.* = [\d.]+/([\d.]+)/[\d.]+/[\d.]+.*ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			// Try alternative format
			re = regexp.MustCompile(`round-trip min/avg/max.* = [\d.]+/([\d.]+)/[\d.]+.*ms`)
			matches = re.FindStringSubmatch(statsLine)
			if len(matches) < 2 {
				return 0, errors.New("failed to parse average latency from ping output")
			}
		}
		avgStr := matches[1]
		avg, errParse = strconv.ParseFloat(avgStr, 64)
	}

	if errParse != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", errParse)
	}

	return avg, nil
}

