    "time"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
    // Validate inputs
    if host == "" {
        return 0, fmt.Errorf("host cannot be empty")
    }
    if count <= 0 {
        return 0, fmt.Errorf("count must be greater than 0")
    }

    // Determine ping command based on OS
    var cmd *exec.Cmd
    switch os := strings.ToLower(os.Getenv("OS")); os {
    case "windows_nt":
        // Windows uses -n for count and -w for timeout (in milliseconds)
        cmd = exec.Command("ping", "-n", strconv.Itoa(count), "-w", "1000", host)
    default:
        // Unix-like systems (Linux, macOS) use -c for count and -W for timeout (in seconds)
        cmd = exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", host)
    }

    // Run the ping command and capture output
    output, err := cmd.CombinedOutput()
    if err != nil {
        // Check if command was not found
        if exitErr, ok := err.(*exec.ExitError); ok && exitErr.ExitCode() != 0 {
            // Ping failed (host unreachable, etc.)
            return 0, fmt.Errorf("ping failed: %v\noutput: %s", err, string(output))
        }
        return 0, fmt.Errorf("failed to execute ping command: %v", err)
    }

    // Parse the output to extract round-trip times
    // Example Linux/macOS output: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=12.3 ms"
    // Example Windows output: "Reply from 8.8.8.8: bytes=32 time=12ms TTL=117"
    lines := strings.Split(string(output), "\n")
    var totalTime float64
    var timeCount int

    for _, line := range lines {
        line = strings.ToLower(line)

        // Skip empty lines
        if strings.TrimSpace(line) == "" {
            continue
        }

        // Parse Unix-like output
        if strings.Contains(line, "time=") {
            // Extract time value
            timeStart := strings.Index(line, "time=")
            if timeStart == -1 {
                continue
            }
            timeStr := line[timeStart+5:]
            // Find end of time value (space or "ms")
            timeEnd := strings.IndexAny(timeStr, " \t")
            if timeEnd == -1 {
                timeEnd = len(timeStr)
            }
            timeStr = timeStr[:timeEnd]
            // Remove "ms" if present
            timeStr = strings.TrimSuffix(timeStr, "ms")

            // Convert to float64
            timeVal, err := strconv.ParseFloat(timeStr, 64)
            if err == nil {
                totalTime += timeVal
                timeCount++
            }
        }

        // Parse Windows output (alternative format)
        if strings.Contains(line, "time=") && strings.Contains(line, "ms") {
            // Windows format: "time=12ms"
            parts := strings.Split(line, "time=")
            if len(parts) < 2 {
                continue
            }
            timePart := parts[1]
            // Extract the numeric part before "ms"
            timeEnd := strings.Index(timePart, "ms")
            if timeEnd == -1 {
                continue
            }
            timeStr := strings.TrimSpace(timePart[:timeEnd])

            // Convert to float64
            timeVal, err := strconv.ParseFloat(timeStr, 64)
            if err == nil {
                totalTime += timeVal
                timeCount++
            }
        }
    }

    // Check if we got any valid times
    if timeCount == 0 {
        return 0, fmt.Errorf("no valid ping times found in output")
    }

    // Calculate average
    average := totalTime / float64(timeCount)
    return average, nil
}

func main() {
    // Example usage
    host := "8.8.8.8" // Google DNS
    count := 4

    fmt.Printf("Pinging %s %d times...\n", host, count)

    start := time.Now()
    latency, err := MeasureLatency(host, count)
    elapsed := time.Since(start)

    if err != nil {
        fmt.Printf("Error: %v\n", err)
        os.Exit(1)
    }

    fmt.Printf("Average latency: %.2f ms\n", latency)
    fmt.Printf("Measurement took: %v\n", elapsed)
}

