package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"runtime"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the appropriate ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// On Windows, ping returns exit code 0 even if host is unreachable
		// So we need to check the output for errors differently
		if runtime.GOOS == "windows" {
			outputStr := string(output)
			if strings.Contains(outputStr, "Request timed out") || 
			   strings.Contains(outputStr, "Destination host unreachable") ||
			   strings.Contains(outputStr, "Ping request could not find host") {
				return 0, fmt.Errorf("ping failed: %s", outputStr)
			}
		} else {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
		}
	}

	outputStr := string(output)

	// Handle different ping output formats for different OSes
	var avg float64
	var parseErr error

	if runtime.GOOS == "windows" {
		avg, parseErr = parseWindowsPingOutput(outputStr)
	} else {
		avg, parseErr = parseUnixPingOutput(outputStr)
	}

	if parseErr != nil {
		return 0, parseErr
	}

	return avg, nil
}

// parseUnixPingOutput parses ping output from Unix-like systems (Linux, macOS)
func parseUnixPingOutput(outputStr string) (float64, error) {
	lines := strings.Split(outputStr, "\n")
	var statsLine string

	// Look for the line containing RTT statistics
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+\s*(ms|msec)?`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// parseWindowsPingOutput parses ping output from Windows systems
func parseWindowsPingOutput(outputStr string) (float64, error) {
	lines := strings.Split(outputStr, "\n")

	// Look for the line containing statistics
	for i, line := range lines {
		if strings.Contains(line, "Average =") {
			// Example line:    Average = 23ms
			re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avgStr := matches[1]
				avg, err := strconv.ParseFloat(avgStr, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
				}
				return avg, nil
			}
		}

		// Alternative format for some Windows versions
		if strings.Contains(line, "Minimum =") && i+1 < len(lines) {
			nextLine := lines[i+1]
			if strings.Contains(nextLine, "Average =") {
				re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
				matches := re.FindStringSubmatch(nextLine)
				if len(matches) >= 2 {
					avgStr := matches[1]
					avg, err := strconv.ParseFloat(avgStr, 64)
					if err != nil {
						return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
					}
					return avg, nil
				}
			}
		}
	}

	return 0, errors.New("could not find average latency in Windows ping output")
}

// Example usage
func main() {
	// Test the function
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

