package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Platform-specific ping command construction
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows ping uses -n for count and doesn't have -c flag
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, BSD) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if this is just a non-zero exit code (which ping often returns even when successful)
		// We'll check if we got valid output by looking for statistics later
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string

	// Different patterns for different platforms
	var patterns = []string{
		"rtt min/avg/max/mdev",           // Linux format
		"round-trip min/avg/max/stddev",  // Some BSD/macOS format
		"Minimum =",                      // Windows format (partial match)
	}

	for _, line := range lines {
		for _, pattern := range patterns {
			if strings.Contains(line, pattern) {
				statsLine = line
				break
			}
		}
		if statsLine != "" {
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Platform-specific regex patterns
	var avgStr string
	var errParse error

	if runtime.GOOS == "windows" {
		// Windows output: Minimum = 12ms, Maximum = 34ms, Average = 23ms
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		} else {
			errParse = errors.New("failed to parse Windows ping output")
		}
	} else {
		// Unix-like output: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		// or: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
		re := regexp.MustCompile(`[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		} else {
			// Try alternative format without mdev/stddev
			reAlt := regexp.MustCompile(`[\d\.]+/([\d\.]+)/[\d\.]+`)
			matchesAlt := reAlt.FindStringSubmatch(statsLine)
			if len(matchesAlt) >= 2 {
				avgStr = matchesAlt[1]
			} else {
				errParse = errors.New("failed to parse Unix ping output")
			}
		}
	}

	if errParse != nil {
		return 0, errParse
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

