func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64
	lines := strings.Split(output, "\n")

	// Regular expressions for different ping output formats
	// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
	// Unix format: "64 bytes from 192.168.1.1: icmp_seq=1 ttl=64 time=0.123 ms"
	winRegex := regexp.MustCompile(`time=(\d+)ms`)
	unixRegex := regexp.MustCompile(`time=([\d.]+)\s*ms`)

