import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use the appropriate ping command based on the operating system
	// For Linux/Unix: ping -c count host
	// For Windows: ping -n count host
	var cmd *exec.Cmd

	// Try Linux/Unix format first
	cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// If Linux/Unix format fails, try Windows format
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		output, err = cmd.CombinedOutput()
		if err != nil {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
		}
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "Average =") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Handle different ping output formats:
	// 1. Linux/Unix: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// 2. Windows: Minimum = 12ms, Maximum = 34ms, Average = 23ms

	var avgStr string

	// Try Linux/Unix format first
	reUnix := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.?\d*/([\d.]+)/\d+\.?\d*/\d+\.?\d*`)
	matchesUnix := reUnix.FindStringSubmatch(statsLine)
	if len(matchesUnix) >= 2 {
		avgStr = matchesUnix[1]
	} else {
		// Try Windows format
		reWindows := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matchesWindows := reWindows.FindStringSubmatch(statsLine)
		if len(matchesWindows) >= 2 {
			avgStr = matchesWindows[1]
		} else {
			// Try alternative Windows format
			reWindowsAlt := regexp.MustCompile(`Average = ([\d.]+)`)
			matchesWindowsAlt := reWindowsAlt.FindStringSubmatch(statsLine)
			if len(matchesWindowsAlt) >= 2 {
				avgStr = matchesWindowsAlt[1]
			} else {
				return 0, errors.New("failed to parse average latency from ping output")
			}
		}
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	latency, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", latency)
}

