// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build the ping command based on the operating system
	var cmd *exec.Cmd
	switch os := getOS(); os {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux", "freebsd", "openbsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system")
	}

	// Capture both stdout and stderr
	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	// Execute the command with a timeout
	done := make(chan error, 1)
	go func() {
		done <- cmd.Run()
	}()

	select {
	case err := <-done:
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %v\nstderr: %s", err, stderr.String())
		}
	case <-time.After(30 * time.Second):
		return 0, fmt.Errorf("ping command timed out after 30 seconds")
	}

	// Parse the output to extract round-trip times
	output := out.String()
	lines := strings.Split(output, "\n")
	var totalRTT float64
	var successfulPings int

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		// Look for lines containing time= or time< (common in ping outputs)
		var timeStr string
		if idx := strings.Index(line, "time="); idx != -1 {
			timeStr = line[idx+5:]
		} else if idx := strings.Index(line, "time<"); idx != -1 {
			timeStr = line[idx+5:]
		} else {
			continue
		}

		// Extract the numeric value (could be followed by ms, etc.)
		timeStr = strings.TrimSpace(timeStr)
		// Remove non-numeric suffix
		for i, r := range timeStr {
			if r < '0' || r > '9' {
				if r == '.' && i > 0 {
					continue // Allow decimal point
				}
				timeStr = timeStr[:i]
				break
			}
		}

		if timeStr == "" {
			continue
		}

		rtt, err := strconv.ParseFloat(timeStr, 64)
		if err != nil {
			continue // Skip malformed lines
		}

		totalRTT += rtt
		successfulPings++
	}

	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful ping responses received")
	}

	return totalRTT / float64(successfulPings), nil
}

// getOS returns a simplified OS identifier
func getOS() string {
	return strings.ToLower(strings.TrimSpace(runtime.GOOS))
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

