package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the appropriate ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if ping failed but still produced output (e.g., partial success)
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue parsing even if there's an error, as ping might have partial results
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Handle different ping output formats
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
		// Windows format: "Minimum = 10ms, Maximum = 20ms, Average = 15ms"
		if strings.Contains(line, "Average =") && strings.Contains(line, "ms") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Try different regex patterns for different ping output formats
	var avgStr string

	// Linux/Unix format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	reUnix := regexp.MustCompile(`rtt min/avg/max.*? = [\d.]+/([\d.]+)/[\d.]+/[\d.]+.*?ms`)
	matches := reUnix.FindStringSubmatch(statsLine)

	if len(matches) < 2 {
		// Alternative Unix format: round-trip min/avg/max = 12.345/23.456/34.567 ms
		reUnixAlt := regexp.MustCompile(`round-trip min/avg/max.*? = [\d.]+/([\d.]+)/[\d.]+.*?ms`)
		matches = reUnixAlt.FindStringSubmatch(statsLine)
	}

	if len(matches) < 2 {
		// Windows format: Minimum = 10ms, Maximum = 20ms, Average = 15ms
		reWindows := regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
		matches = reWindows.FindStringSubmatch(statsLine)
	}

	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr = matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

