// parsePingOutput extracts the average latency from ping command output.
// The output format differs between Windows and Unix-like systems.
func parsePingOutput(output string, isWindows bool) (float64, error) {
	if isWindows {
		// Windows ping output example:
		// "Minimum = 10ms, Maximum = 20ms, Average = 15ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
