package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build the ping command based on the operating system
	var cmd *exec.Cmd
	switch os := strings.ToLower(os.Getenv("OS")); {
	case strings.Contains(os, "windows"):
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	// Parse the output to extract round-trip times
	latencies, err := parsePingOutput(out.String())
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	sum := 0.0
	for _, l := range latencies {
		sum += l
	}
	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts round-trip times (in milliseconds) from ping command output.
// It handles common output formats from Windows and Unix-like systems.
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64
	lines := strings.Split(output, "\n")

	// Patterns for extracting times
	patterns := []*regexp.Regexp{
		// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
		regexp.MustCompile(`time[=<>](\d+(?:\.\d+)?)\s*ms`),
		// Unix format: "64 bytes from 192.168.1.1: icmp_seq=1 ttl=64 time=0.123 ms"
		regexp.MustCompile(`time[=<>](\d+(?:\.\d+)?)\s*ms`),
		// Alternative Unix format: "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.012 ms"
		regexp.MustCompile(`=\s*(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)\s*ms`),
	}

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		// Try each pattern
		for _, pattern := range patterns {
			matches := pattern.FindStringSubmatch(line)
			if matches == nil {
				continue
			}

			// For rtt summary line (pattern 3), use the average value (second capture group)
			if len(matches) > 2 {
				if val, err := strconv.ParseFloat(matches[2], 64); err == nil {
					latencies = append(latencies, val)
					break
				}
			} else if len(matches) > 1 {
				// For individual ping times (patterns 1 and 2)
				if val, err := strconv.ParseFloat(matches[1], 64); err == nil {
					latencies = append(latencies, val)
					break
				}
			}
		}
	}

	return latencies, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

