// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	// Determine the ping command based on the operating system
	var cmd *exec.Cmd
	if isWindows() {
		// Windows ping format: ping -n count host
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS) ping format: ping -c count host
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture the output
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	// Execute the ping command
	err := cmd.Run()
	if err != nil {
		// Some ping implementations return non-zero exit status even on successful pings
		// We'll still try to parse the output if there is any
		if out.Len() == 0 {
			return 0, fmt.Errorf("ping command failed: %v", err)
		}
	}

	// Parse the output to extract round-trip times
	latencies, err := parsePingOutput(out.String(), isWindows())
	if err != nil {
		return 0, err
	}

	// Calculate average latency
	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency data found in ping output")
	}

	var sum float64
	for _, lat := range latencies {
		sum += lat
	}
	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts round-trip times from ping command output.
func parsePingOutput(output string, isWindows bool) ([]float64, error) {
	var latencies []float64
	lines := strings.Split(output, "\n")

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		// Parse based on OS
		if isWindows {
			// Windows ping output format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
			if strings.Contains(line, "time=") {
				start := strings.Index(line, "time=")
				if start == -1 {
					continue
				}
				timeStr := line[start+5:]
				end := strings.Index(timeStr, "ms")
				if end == -1 {
					continue
				}
				timeStr = timeStr[:end]
				lat, err := strconv.ParseFloat(timeStr, 64)
				if err == nil {
					latencies = append(latencies, lat)
				}
			}
		} else {
			// Unix-like ping output format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=12.8 ms"
			if strings.Contains(line, "time=") {
				// Find the time value
				timeIndex := strings.Index(line, "time=")
				if timeIndex == -1 {
					continue
				}
				timePart := line[timeIndex+5:]
				// Remove "ms" suffix if present
				timePart = strings.TrimSuffix(timePart, " ms")
				// Handle cases where there might be additional text after the time
				if spaceIndex := strings.Index(timePart, " "); spaceIndex != -1 {
					timePart = timePart[:spaceIndex]
				}
				lat, err := strconv.ParseFloat(timePart, 64)
				if err == nil {
					latencies = append(latencies, lat)
				}
			}
		}
	}

	return latencies, nil
}

// isWindows returns true if the operating system is Windows.
func isWindows() bool {
	// Check the GOOS environment variable
	return strings.Contains(strings.ToLower(exec.Command("cmd").Path), "windows") ||
		strings.Contains(strings.ToLower(osInfo()), "windows")
}

// osInfo returns a string with OS information (simplified version).
func osInfo() string {
	cmd := exec.Command("uname", "-s")
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Run()
	if out.Len() > 0 {
		return out.String()
	}
	return ""
}

func main() {
	// Example usage
