        //     Packets: Sent = 4, Received = 4, Lost = 0 (0% loss),
        // Approximate round trip times in milli-seconds:
        //     Minimum = 12ms, Maximum = 15ms, Average = 13ms
        re := regexp.MustCompile(`time=(\d+)ms`)
        for scanner.Scan() {
            line := scanner.Text()
            matches := re.FindStringSubmatch(line)
            if len(matches) == 2 {
                latency, err := strconv.ParseFloat(matches[1], 64)
                if err == nil {
                    latencies = append(latencies, latency)
                }
            }
        }
    } else {
        // Unix-like ping output example:
        // 64 bytes from 8.8.8.8: icmp_seq=0 ttl=116 time=12.3 ms
        // 64 bytes from 8.8.8.8: icmp_seq=1 ttl=116 time=15.7 ms
        // ...
        // --- 8.8.8.8 ping statistics ---
        // 4 packets transmitted, 4 received, 0% packet loss, time 3004ms
        // rtt min/avg/max/mdev = 12.345/13.456/15.678/1.234 ms
        re := regexp.MustCompile(`time=([\d.]+)\s*ms`)
        for scanner.Scan() {
            line := scanner.Text()
            matches := re.FindStringSubmatch(line)
            if len(matches) == 2 {
                latency, err := strconv.ParseFloat(matches[1], 64)
                if err == nil {
                    latencies = append(latencies, latency)
                }
            }
        }
    }

    if err := scanner.Err(); err != nil {
        return nil, err
    }

    return latencies, nil
}

// isWindows returns true if the operating system is Windows.
func isWindows() bool {
    // This is a simplified check. In a real application, you might use runtime.GOOS.
    // For this example, we'll check the presence of Windows-specific environment variables.
    // A more robust approach would be to use the "runtime" package.
    return strings.Contains(strings.ToLower(os.Getenv("OS")), "windows") ||
        strings.Contains(strings.ToLower(os.Getenv("PATH")), "\\windows\\")
}

