// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
// host: target hostname or IP address
// count: number of ping attempts (must be positive)
// Returns: average latency in milliseconds, or error if ping fails
func MeasureLatency(host string, count int) (float64, error) {
    if count <= 0 {
        return 0, fmt.Errorf("count must be positive, got %d", count)
    }

    if host == "" {
        return 0, fmt.Errorf("host cannot be empty")
    }

    // Build ping command based on OS
    var cmd *exec.Cmd
    switch runtime.GOOS {
    case "windows":
        cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
    case "darwin", "linux", "freebsd", "openbsd", "netbsd":
        cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
    default:
        return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
    }

    // Execute ping command
    var out bytes.Buffer
    cmd.Stdout = &out
    cmd.Stderr = &out

    if err := cmd.Run(); err != nil {
        return 0, fmt.Errorf("ping command failed: %v\nOutput: %s", err, out.String())
    }

    // Parse output to extract latency values
    output := out.String()
    var totalLatency float64
    var successfulPings int

    lines := strings.Split(output, "\n")
    for _, line := range lines {
        line = strings.TrimSpace(line)

        // Different parsing for different OS
        if runtime.GOOS == "windows" {
            // Windows format: "Reply from 8.8.8.8: bytes=32 time=12ms TTL=114"
            if strings.Contains(line, "time=") && strings.Contains(line, "TTL=") {
                parts := strings.Split(line, "time=")
                if len(parts) > 1 {
                    timePart := strings.Split(parts[1], "ms")[0]
                    if latency, err := strconv.ParseFloat(timePart, 64); err == nil {
                        totalLatency += latency
                        successfulPings++
                    }
                }
            }
        } else {
            // Unix-like format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=114 time=12.345 ms"
            if strings.Contains(line, "time=") && strings.Contains(line, "icmp_seq") {
                parts := strings.Split(line, "time=")
                if len(parts) > 1 {
                    timePart := strings.Split(parts[1], " ")[0]
                    if latency, err := strconv.ParseFloat(timePart, 64); err == nil {
                        totalLatency += latency
                        successfulPings++
                    }
                }
            }
        }
    }

    // Check if we got any successful pings
    if successfulPings == 0 {
        return 0, fmt.Errorf("no successful ping responses received")
    }

    // Calculate average latency
    averageLatency := totalLatency / float64(successfulPings)
    return averageLatency, nil
}

func main() {
    // Example usage
    host := "8.8.8.8"  // Google DNS
    count := 4

    latency, err := MeasureLatency(host, count)
    if err != nil {
        fmt.Printf("Error measuring latency: %v\n", err)
        return
    }

    fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

