    // Parse the output to extract the average latency
    avgLatency, err := parsePingOutput(string(output))
    if err != nil {
        return 0, fmt.Errorf("failed to parse ping output: %v", err)
    }

    return avgLatency, nil
}

// parsePingOutput extracts the average round-trip time from ping command output.
// It handles different formats for Windows and Unix-like systems.
func parsePingOutput(output string) (float64, error) {
    lines := strings.Split(output, "\n")

    // Try to parse Unix-like output first (Linux, macOS)
    for _, line := range lines {
        if strings.Contains(line, "rtt min/avg/max/mdev") || 
           strings.Contains(line, "round-trip min/avg/max/stddev") {
            // Example: "rtt min/avg/max/mdev = 12.345/67.890/123.456/12.345 ms"
            parts := strings.Split(line, "=")
            if len(parts) != 2 {
                continue
            }
            stats := strings.Fields(parts[1])[0] // Get "12.345/67.890/123.456/12.345"
            values := strings.Split(stats, "/")
            if len(values) >= 2 {
                avg, err := strconv.ParseFloat(values[1], 64)
                if err != nil {
                    return 0, fmt.Errorf("failed to parse average latency: %v", err)
                }
                return avg, nil
            }
        }
    }

    // Try to parse Windows output
    for _, line := range lines {
        if strings.Contains(line, "Average =") {
            // Example: "Average = 45ms"
            parts := strings.Split(line, "=")
            if len(parts) != 2 {
                continue
            }
            // Extract numeric value and remove "ms" suffix
            valueStr := strings.TrimSpace(parts[1])
            valueStr = strings.TrimSuffix(valueStr, "ms")
            avg, err := strconv.ParseFloat(valueStr, 64)
            if err != nil {
                return 0, fmt.Errorf("failed to parse average latency: %v", err)
            }
            return avg, nil
        }
    }

    return 0, fmt.Errorf("could not find average latency in ping output")
}

// isWindows checks if the current operating system is Windows.
func isWindows() bool {
    return strings.Contains(strings.ToLower(os.Getenv("OS")), "windows") ||
           strings.Contains(strings.ToLower(runtime.GOOS), "windows")
}

// Example usage in main function
func main() {
    // Example 1: Ping google.com 4 times
    host := "google.com"
    count := 4

    fmt.Printf("Measuring latency to %s with %d ping attempts...\n", host, count)

    start := time.Now()
    avgLatency, err := MeasureLatency(host, count)
    elapsed := time.Since(start)

    if err != nil {
        fmt.Printf("Error: %v\n", err)
        os.Exit(1)
    }

    fmt.Printf("Average latency: %.2f ms\n", avgLatency)
    fmt.Printf("Measurement completed in %v\n", elapsed)

    // Example 2: Ping localhost 2 times
    fmt.Println("\n--- Testing with localhost ---")
    avgLatency2, err2 := MeasureLatency("localhost", 2)
    if err2 != nil {
        fmt.Printf("Error: %v\n", err2)
    } else {
        fmt.Printf("Average latency to localhost: %.2f ms\n", avgLatency2)
    }
}

