// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the appropriate ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count and doesn't support single quotes
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if the error is due to non-zero exit status (ping can succeed but return non-zero)
		// We'll still try to parse the output if we have some
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue to parse output even if there's an error, as ping might have succeeded partially
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Handle different ping output formats
		if strings.Contains(line, "rtt min/avg/max") || 
		   strings.Contains(line, "round-trip min/avg/max") ||
		   (runtime.GOOS == "windows" && strings.Contains(line, "Average =")) {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	var avg float64
	var parseErr error

	if runtime.GOOS == "windows" {
		// Windows ping output format: Minimum = 10ms, Maximum = 20ms, Average = 15ms
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from Windows ping output")
		}
		avgStr := matches[1]
		avg, parseErr = strconv.ParseFloat(avgStr, 64)
	} else {
		// Unix ping output format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		// Handle both formats with and without mdev
		re := regexp.MustCompile(`[\d.]+/([\d.]+)/[\d.]+`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			// Try alternative format without mdev
			re = regexp.MustCompile(`[\d.]+/([\d.]+)/[\d.]+/[\d.]+`)
			matches = re.FindStringSubmatch(statsLine)
		}

		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avgStr := matches[1]
		avg, parseErr = strconv.ParseFloat(avgStr, 64)
	}

	if parseErr != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", parseErr)
	}

	return avg, nil
}

