func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine ping command arguments based on OS
	var cmdArgs []string
	switch os := strings.ToLower(os.Getenv("GOOS")); os {
	case "windows":
		cmdArgs = []string{"-n", strconv.Itoa(count), "-w", "1000", host}
