	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	// Parse output to extract round-trip times
	avgLatency, err := parsePingOutput(out.String(), os.Getenv("GOOS"))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	return avgLatency, nil
}

// parsePingOutput extracts the average latency from ping command output.
// It handles different output formats for Windows and Unix-like systems.
func parsePingOutput(output, goos string) (float64, error) {
	var pattern string
	if strings.ToLower(goos) == "windows" {
		// Windows ping output: "Average = 10ms"
		pattern = `Average\s*=\s*(\d+)ms`
	} else {
		// Unix ping output: "rtt min/avg/max/mdev = 10.123/20.456/30.789/5.678 ms"
		pattern = `rtt.*?=\s*[\d.]+\/([\d.]+)\/[\d.]+\/[\d.]+ ms`
	}

	re := regexp.MustCompile(pattern)
	matches := re.FindStringSubmatch(output)
	if matches == nil || len(matches) < 2 {
		return 0, fmt.Errorf("could not find average latency in ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value '%s': %v", avgStr, err)
	}

	return avg, nil
}

func main() {
