	}

	// Parse the output to extract latency values
	latencies, err := parsePingOutput(out.String(), getOS())
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	// Calculate average latency
	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency data found in ping output")
	}

	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	average := sum / float64(len(latencies))

	return average, nil
}

// getOS returns a normalized string representing the current OS
func getOS() string {
	// Use runtime.GOOS instead of environment variable for reliability
	return strings.ToLower(runtime.GOOS)
}

// parsePingOutput extracts latency values from ping command output
// based on the operating system format
func parsePingOutput(output string, os string) ([]float64, error) {
	var latencies []float64
	var pattern string

	switch os {
	case "windows":
		// Windows ping output example: "Reply from 8.8.8.8: bytes=32 time=12ms TTL=116"
		pattern = `time=(\d+)ms`
	case "linux", "darwin", "freebsd":
		// Unix ping output example: "64 bytes from 8.8.8.8: icmp_seq=1 ttl=116 time=12.345 ms"
		pattern = `time=([\d.]+)\s*ms`
	default:
		return nil, fmt.Errorf("unsupported operating system for parsing")
	}

	re := regexp.MustCompile(pattern)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return nil, fmt.Errorf("no latency data found in output")
	}

	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		latencyStr := match[1]
		latency, err := strconv.ParseFloat(latencyStr, 64)
		if err != nil {
			// Skip invalid latency values but continue processing others
			continue
		}
		latencies = append(latencies, latency)
	}

	return latencies, nil
}

// main function demonstrates usage of MeasureLatency
func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

